ALTER DATABASE CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
CREATE TABLE `priv_user` (`id` INT(11) NOT NULL AUTO_INCREMENT PRIMARY KEY, `contactid` INT(11) DEFAULT 0, INDEX `contactid` (`contactid`), `login` VARCHAR(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT '', INDEX `login` (`login` (95)), `language` VARCHAR(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'EN US', INDEX `language` (`language` (95)), `status` ENUM('enabled','disabled') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'enabled', `log` LONGTEXT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci, `log_index` BLOB, `finalclass` VARCHAR(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'User', INDEX `finalclass` (`finalclass` (95))) ENGINE = innodb CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci
